#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1<<16|7;vector<int> G[N],I[N];
int n,deg[N],stk[N],top,P[N],cpt,fa[18][N],dep[N],siz[N];
inline int LCA(int u,int v)
{
	if(u==-1)return v;if(v==-1)return u;
	if(dep[u]<dep[v])swap(u,v);
	drep(17,0,i)if(dep[fa[i][u]]>=dep[v])u=fa[i][u];
	drep(17,0,i)if(fa[i][u]!=fa[i][v])u=fa[i][u],v=fa[i][v];
	return u==v?u:fa[0][u];
}
int main()
{
//	FIN("P2597_5.in");
//	FOUT("mine.out");
	n=read();rep(1,n,i)
	{
		int x=read();while(x)
		{
			G[x].push_back(i);
			I[i].push_back(x);
			x=read();
		}
		deg[i]=I[i].size();
	}
	rep(1,n,i)if(!deg[i])
	{
		G[0].push_back(i);
		I[i].push_back(0);++deg[i];
	}
	stk[top=1]=0;while(top)
	{
		int u=stk[top--];P[++cpt]=u;
		for(int v:G[u])if(!(--deg[v]))stk[++top]=v;
	}
	rep(2,cpt,i)
	{
		int u=P[i],lca=-1;for(int v:I[u])lca=LCA(lca,v);
		fa[0][u]=lca;dep[u]=dep[lca]+1;siz[u]=1;
		rep(1,17,j)fa[j][u]=fa[j-1][fa[j-1][u]];
	}
	drep(cpt,2,i)siz[fa[0][P[i]]]+=siz[P[i]];
//	rep(1,n,i)printf("%d ",fa[0][i]);puts("");
	rep(1,n,i)printf("%d\n",siz[i]-1);
}
